// Function to find quadruplets with sum = target
void fourSum(int arr[], int n, int target) {
    // Use four nested loops to generate all possible quadruplets
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            for (int k = j + 1; k < n; k++) {
                for (int l = k + 1; l < n; l++) {
                    // Calculate sum of four chosen numbers
                    int sum = arr[i] + arr[j] + arr[k] + arr[l];
                    // Check if sum matches target
                    if (sum == target) {
                        printf("[%d, %d, %d, %d]", arr[i], arr[j], arr[k], arr[l]);
