class Solution {
    // Function to find quadruplets with sum = target
    fourSum(arr, target) {
        // Get size of array
        let n = arr.length;
        // Use set to avoid duplicates
        let st = new Set();

        // First loop - pick first element
        for (let i = 0; i < n; i++) {
            // Second loop - pick second element
            for (let j = i + 1; j < n; j++) {
                // Third loop - pick third element
                for (let k = j + 1; k < n; k++) {
                    // Fourth loop - pick fourth element
                    for (let l = k + 1; l < n; l++) {
                        // Calculate sum
                        let sum = arr[i] + arr[j] + arr[k] + arr[l];
                        // If sum equals target
                        if (sum === target) {
                            // Create quadruplet
                            let temp = [arr[i], arr[j], arr[k], arr[l]];
                            // Sort it to avoid duplicates
                            temp.sort((a, b) => a - b);
                            // Store as string in set
                            st.add(JSON.stringify(temp));
                        }
                    }
                }
            }
        }

        // Convert set back to array of arrays
        return Array.from(st).map(JSON.parse);
    }
}

